#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long prev, cur, ans = 0;
        scanf("%lld", &prev);
        for (int i = 1; i < N; ++i) {
            scanf("%lld", &cur);
            long long diff = llabs(cur - prev) - 1;
            if (diff > 0) ans += diff;
            prev = cur;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

