#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        prev = next(it)
        ans = 0
        for _ in range(N-1):
            cur = next(it)
            diff = abs(cur - prev) - 1
            if diff > 0:
                ans += diff
            prev = cur
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

